          <div className="absolute inset-0 bg-gradient-to-t from-brand-obsidian via-transparent to-transparent opacity-60 group-hover:opacity-80 transition-opacity" />

          <div className="absolute bottom-10 left-10 text-white z-10">
            <span className="font-mono text-brand-blue text-sm uppercase tracking-widest mb-2 block font-bold">
              {project.category}
            </span>
            <h3 className="text-4xl md:text-6xl font-black tracking-tighter group-hover:translate-x-4 transition-transform duration-500">
              {project.title}
            </h3>
