import React, { useRef, useMemo } from 'react';
import { Canvas, useFrame, useThree } from '@react-three/fiber';
import * as THREE from 'three';
import { useScroll } from 'framer-motion';

const Blob = ({ color, position, scale, speed, mouseRef }: any) => {
  const meshRef = useRef<THREE.Mesh>(null!);
  const initialPos = useMemo(() => new THREE.Vector3(...position), [position]);

  useFrame((state) => {
    const time = state.clock.getElapsedTime();
    const scroll = window.scrollY / (document.body.scrollHeight - window.innerHeight);

    // Subtle drift
    meshRef.current.position.x = initialPos.x + Math.sin(time * speed) * 5;
    meshRef.current.position.y = initialPos.y + Math.cos(time * speed * 0.8) * 5;

    // Mouse follow with damping
    const targetX = state.mouse.x * 20;
    const targetY = state.mouse.y * 10;
    meshRef.current.position.x += (targetX - meshRef.current.position.x) * 0.02;
    meshRef.current.position.y += (targetY - meshRef.current.position.y) * 0.02;

    // Scroll distortion
    const distortionScale = 1 + scroll * 1.5;
    meshRef.current.scale.set(scale[0] * distortionScale, scale[1] * distortionScale, scale[2]);
  });

  return (
    <mesh ref={meshRef} position={position}>
