import React, { useRef, useMemo } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import * as THREE from 'three';

const Blob = ({ color, position, scale, speed }: { color: string, position: [number, number, number], scale: [number, number, number], speed: number }) => {
  const meshRef = useRef<THREE.Mesh>(null!);
  const initialPos = useMemo(() => new THREE.Vector3(...position), [position]);

  useFrame((state) => {
    const time = state.clock.getElapsedTime();
    const scroll = window.scrollY / (document.body.scrollHeight - window.innerHeight);

    // Dynamic drifting movement
    meshRef.current.position.x = initialPos.x + Math.sin(time * speed) * 8;
    meshRef.current.position.y = initialPos.y + Math.cos(time * speed * 0.7) * 8;

    // Responsive mouse follow with high damping
    const targetX = state.mouse.x * 25;
    const targetY = state.mouse.y * 15;
    meshRef.current.position.x += (targetX - meshRef.current.position.x) * 0.01;
    meshRef.current.position.y += (targetY - meshRef.current.position.y) * 0.01;

    // Scroll-based expansion/warping
    const distortionScale = 1 + scroll * 1.8;
    meshRef.current.scale.set(
      scale[0] * distortionScale,
      scale[1] * distortionScale,
      scale[2]
    );
  });

  return (
    <mesh ref={meshRef} position={position}>
      <sphereGeometry args={[1, 64, 64]} />
      <meshBasicMaterial color={color} transparent opacity={0.65} />
    </mesh>
  );
};

