import React, { useRef, useMemo } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import * as THREE from 'three';

const Blob = ({ color, position, scale, speed, index }: { color: string, position: [number, number, number], scale: [number, number, number], speed: number, index: number }) => {
  const meshRef = useRef<THREE.Mesh>(null!);
  const initialPos = useMemo(() => new THREE.Vector3(...position), [position]);

  useFrame((state) => {
    const time = state.clock.getElapsedTime();
    // Normalize scroll (0 to 1)
    const scroll = window.scrollY / (document.body.scrollHeight - window.innerHeight || 1);

    // 1. Time-based drifting movement
    const driftX = Math.sin(time * speed) * 5;
    const driftY = Math.cos(time * speed * 0.8) * 5;

    // 2. Scroll-based parallax movement
    // Blobs move vertically and horizontally at different rates based on their index
    const scrollFactorY = (index % 2 === 0 ? 1 : -1) * 30;
    const scrollFactorX = (index % 3 === 0 ? 1 : -1) * 15;

    const targetY = initialPos.y + driftY - (scroll * scrollFactorY);
    const targetX = initialPos.x + driftX + (scroll * scrollFactorX);

    // 3. Mouse follow with damping
    const mouseX = state.mouse.x * 20;
    const mouseY = state.mouse.y * 10;

    meshRef.current.position.x = THREE.MathUtils.lerp(meshRef.current.position.x, targetX + mouseX, 0.03);
    meshRef.current.position.y = THREE.MathUtils.lerp(meshRef.current.position.y, targetY + mouseY, 0.03);

    // 4. Scroll-based expansion/warping
    const distortionScale = 1 + scroll * 1.5;
    meshRef.current.scale.set(
      scale[0] * distortionScale,
      scale[1] * distortionScale,
      scale[2]
    );

    // 5. Opacity pulse
    const material = meshRef.current.material as THREE.MeshBasicMaterial;
    material.opacity = 0.4 + Math.sin(time * speed) * 0.2;
  });

  return (
    <mesh ref={meshRef} position={position}>
      <sphereGeometry args={[1, 64, 64]} />
      <meshBasicMaterial color={color} transparent opacity={0.6} />
    </mesh>
  );
};

