import React, { useRef, useMemo, useEffect, useState } from 'react';
import { Canvas, useFrame, useThree } from '@react-three/fiber';
import * as THREE from 'three';

const VERTEX_SHADER = `
  varying vec2 vUv;
  void main() {
    vUv = uv;
    gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
  }
`;

const FRAGMENT_SHADER = `
  precision highp float;
  varying vec2 vUv;
  uniform float uTime;
  uniform float uScroll;
  uniform vec2 uMouse;
  uniform float uIntensity;

  // Simple Noise function
  float hash(vec2 p) {
    p = fract(p * vec2(123.34, 456.21));
    p += dot(p, p + 45.32);
    return fract(p.x * p.y);
  }

  float noise(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    float a = hash(i);
    float b = hash(i + vec2(1.0, 0.0));
    float c = hash(i + vec2(0.0, 1.0));
    float d = hash(i + vec2(1.0, 1.0));
    vec2 u = f * f * (3.0 - 2.0 * f);
    return mix(a, b, u.x) + (c - a) * u.y * (1.0 - u.x) + (d - b) * u.x * u.y;
  }

  void main() {
    vec2 uv = vUv;

    // Create liquid motion base
    float scrollEffect = uScroll * 1.5;
    float time = uTime * 0.15;

    // Distortion from mouse
    float dist = distance(uv, uMouse);
    float mouseStrength = 0.08 / (dist + 0.1);

    // Layered Noise for silk effect
    float n = noise(uv * 3.0 + time + scrollEffect);
    n += noise(uv * 6.0 - time * 0.5) * 0.5;
    n += noise(uv * 12.0 + time * 0.2) * 0.25;

    // Displacement logic
    vec2 displacement = vec2(n * 0.1, n * 0.1) * (1.0 + scrollEffect);
    displacement += (uv - uMouse) * mouseStrength * 0.05;

    // Final color mapping (Obsidian and Brand Blue)
    vec3 obsidian = vec3(0.02, 0.02, 0.03);
    vec3 brandBlue = vec3(0.0, 0.4, 1.0);
    vec3 deepBlue = vec3(0.0, 0.05, 0.2);

    // Create gradients based on noise and displacement
    float mixVal = smoothstep(0.4, 0.7, n + scrollEffect * 0.2);
    vec3 color = mix(obsidian, deepBlue, n * 0.4);
    color = mix(color, brandBlue, mixVal * 0.3);

    // High intensity flash on scroll
    color += brandBlue * (uIntensity * 0.05);

    gl_FragColor = vec4(color, 1.0);
  }
`;

const InteractivePlane = () => {
  const meshRef = useRef<THREE.Mesh>(null!);
  const { viewport, size } = useThree();
  const [isMobile, setIsMobile] = useState(false);

  useEffect(() => {
    setIsMobile(window.innerWidth < 768);
  }, []);

  const uniforms = useMemo(() => ({
    uTime: { value: 0 },
    uScroll: { value: 0 },
    uMouse: { value: new THREE.Vector2(0.5, 0.5) },
    uIntensity: { value: 0 }
  }), []);

  useFrame((state) => {
    const { clock, mouse } = state;
    uniforms.uTime.value = clock.getElapsedTime();

    // Smooth scroll update
    const targetScroll = window.scrollY / (document.body.scrollHeight - window.innerHeight || 1);
    uniforms.uScroll.value = THREE.MathUtils.lerp(uniforms.uScroll.value, targetScroll, 0.05);

    // Mouse interpolation (Passive on mobile)
    if (!isMobile) {
      const targetMouseX = (mouse.x + 1) / 2;
      const targetMouseY = (mouse.y + 1) / 2;
      uniforms.uMouse.value.x = THREE.MathUtils.lerp(uniforms.uMouse.value.x, targetMouseX, 0.1);
      uniforms.uMouse.value.y = THREE.MathUtils.lerp(uniforms.uMouse.value.y, targetMouseY, 0.1);
    }

    // Scroll intensity flash
    const scrollVelocity = Math.abs(uniforms.uScroll.value - targetScroll);
    uniforms.uIntensity.value = THREE.MathUtils.lerp(uniforms.uIntensity.value, scrollVelocity * 50, 0.1);
  });

  return (
    <mesh ref={meshRef} scale={[viewport.width, viewport.height, 1]}>
      <planeGeometry args={[1, 1, 32, 32]} />
      <shaderMaterial 
        vertexShader={VERTEX_SHADER}
        fragmentShader={FRAGMENT_SHADER}
        uniforms={uniforms}
        transparent
      />
    </mesh>
  );
};

const BackgroundCanvas: React.FC = () => {
  return (
    <div className="fixed inset-0 z-0 pointer-events-none">
      <Canvas 
        camera={{ position: [0, 0, 1] }} 
        dpr={[1, 2]}
        gl={{ antialias: true, stencil: false, depth: false }}
      >
        <InteractivePlane />
      </Canvas>
      <div className="absolute inset-0 bg-brand-obsidian/20 pointer-events-none" />
    </div>
  );
};

