    vec2 i = floor(p);
    vec2 f = fract(p);
    float a = hash(i);
    float b = hash(i + vec2(1.0, 0.0));
    float c = hash(i + vec2(0.0, 1.0));
    float d = hash(i + vec2(1.0, 1.0));
    vec2 u = f * f * (3.0 - 2.0 * f);
    return mix(a, b, u.x) + (c - a) * u.y * (1.0 - u.x) + (d - b) * u.x * u.y;
  }

  void main() {
    vec2 uv = vUv;
    float scrollEffect = uScroll * 1.2;
    float time = uTime * 0.12;

    float dist = distance(uv, uMouse);
    float mouseStrength = 0.05 / (dist + 0.15);

    float n = noise(uv * 2.5 + time + scrollEffect);
    n += noise(uv * 5.0 - time * 0.4) * 0.4;

    vec2 displacement = vec2(n * 0.08, n * 0.08);
    displacement += (uv - uMouse) * mouseStrength * 0.03;

