    vec3 baseColor = vec3(0.01, 0.01, 0.02);
    vec3 accentBlue = vec3(0.0, 0.25, 0.7); // Darker blue to avoid camouflage
    vec3 subtleGlow = vec3(0.0, 0.05, 0.15);

