    vec3 color = mix(baseColor, subtleGlow, n * 0.3);
    color = mix(color, accentBlue, mixVal * 0.2); // Only 20% accent blue to keep it dark

    // Reactive intensity from scroll
    color += accentBlue * (uIntensity * 0.03);

    gl_FragColor = vec4(color, 1.0);
  }
