    uniforms.uIntensity.value = THREE.MathUtils.lerp(uniforms.uIntensity.value, scrollVelocity * 100, 0.1);
  });

  return (
    <Mesh ref={meshRef} scale={[viewport.width, viewport.height, 1]}>
      <PlaneGeometry args={[1, 1, 32, 32]} />
      <ShaderMaterial 
        vertexShader={VERTEX_SHADER}
        fragmentShader={FRAGMENT_SHADER}
        uniforms={uniforms}
        transparent
      />
    </Mesh>
  );
};

