export type View = 'home' | 'services' | 'work' | 'contact';

const App: React.FC = () => {
  const [isLoaderActive, setIsLoaderActive] = useState(true);
  const [showContent, setShowContent] = useState(false);
  const [currentView, setCurrentView] = useState<View>('home');

  // Smooth Scroll Initialization
  useEffect(() => {
    const lenis = new Lenis({
      duration: 1.2,
      easing: (t) => Math.min(1, 1.001 - Math.pow(2, -10 * t)),
      orientation: 'vertical',
      gestureOrientation: 'vertical',
      smoothWheel: true,
      wheelMultiplier: 1,
      touchMultiplier: 2,
      infinite: false,
    });

    function raf(time: number) {
      lenis.raf(time);
      requestAnimationFrame(raf);
    }

    requestAnimationFrame(raf);

    // Ensure scroll position resets on view change if needed
    // or manually scroll to top
    window.scrollTo(0, 0);

    return () => {
      lenis.destroy();
    };
  }, [currentView]); // Re-init or reset on view change

  useEffect(() => {
    // Artificial delay for the "Drawing" logo effect
    const timer = setTimeout(() => {
      setIsLoaderActive(false);
      // Wait for curtains to slide before showing standard layout elements
      setTimeout(() => setShowContent(true), 1200);
    }, 2800);
    return () => clearTimeout(timer);
  }, []);

  const renderView = () => {
    switch (currentView) {
      case 'home': return <Home onNavigate={setCurrentView} />;
      case 'services': return <Services />;
      case 'work': return <Work />;
      case 'contact': return <Contact />;
      default: return <Home onNavigate={setCurrentView} />;
    }
  };

  return (
    <div className="relative min-h-screen bg-brand-obsidian font-sans selection:bg-brand-blue selection:text-white">
      <AnimatePresence mode="wait">
        {isLoaderActive && <CurtainLoader key="loader" />}
      </AnimatePresence>

      <CustomCursor />

      {/* High-Performance WebGL Background */}
      <BackgroundCanvas />

      {showContent && (
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ duration: 1, ease: "easeOut" }}
          className="relative z-20"
        >
          <Header currentView={currentView} onNavigate={setCurrentView} />

          <motion.main className="relative z-10 pt-20">
            <AnimatePresence mode="wait">
              <motion.div
                key={currentView}
                initial={{ opacity: 0, y: 15 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -15 }}
                transition={{ duration: 0.5, ease: [0.22, 1, 0.36, 1] }}
              >
                {renderView()}
              </motion.div>
            </AnimatePresence>
            <Footer onNavigate={setCurrentView} />
          </motion.main>
        </motion.div>
      )}
    </div>
  );
};

