import React, { useRef, useMemo, useEffect, useState } from 'react';
import { Canvas, useFrame, useThree } from '@react-three/fiber';
import * as THREE from 'three';

const Points = 'points' as any;
const BufferGeometry = 'bufferGeometry' as any;
const BufferAttribute = 'bufferAttribute' as any;
const PointsMaterial = 'pointsMaterial' as any;

const StarField = () => {
  const pointsRef = useRef<THREE.Points>(null!);
  const [isMobile, setIsMobile] = useState(false);
  const scrollPos = useRef(0);
  const velocity = useRef(0);
  const lastScroll = useRef(0);

  useEffect(() => {
    const checkMobile = () => setIsMobile(window.innerWidth < 768);
    checkMobile();
    window.addEventListener('resize', checkMobile);

    const handleScroll = () => {
      scrollPos.current = window.scrollY;
    };
    window.addEventListener('scroll', handleScroll, { passive: true });

    return () => {
      window.removeEventListener('resize', checkMobile);
      window.removeEventListener('scroll', handleScroll);
    };
  }, []);

  const count = isMobile ? 1500 : 5000;

  // Create stars in a tunnel distribution (Z-axis focus)
  const [positions, sizes] = useMemo(() => {
    const pos = new Float32Array(count * 3);
    const sz = new Float32Array(count);
    for (let i = 0; i < count; i++) {
      // Cylindrical distribution for tunnel effect
      const r = 20 + Math.random() * 80;
      const theta = Math.random() * Math.PI * 2;
      pos[i * 3] = Math.cos(theta) * r;
      pos[i * 3 + 1] = Math.sin(theta) * r;
      pos[i * 3 + 2] = (Math.random() - 0.5) * 500; // Deep Z axis
      sz[i] = Math.random() * 2;
    }
    return [pos, sz];
  }, [count]);

  useFrame((state) => {
    const { mouse, clock } = state;
    const time = clock.getElapsedTime();

    // Calculate scroll velocity
    const currentScroll = scrollPos.current;
    const scrollDelta = currentScroll - lastScroll.current;
    velocity.current = THREE.MathUtils.lerp(velocity.current, Math.abs(scrollDelta) * 0.1, 0.1);
    lastScroll.current = currentScroll;

    // Warp speed effect: Stars move towards camera
    const baseSpeed = 0.2;
    const currentSpeed = baseSpeed + velocity.current * 2;

    const posArray = pointsRef.current.geometry.attributes.position.array as Float32Array;

    for (let i = 0; i < count; i++) {
      posArray[i * 3 + 2] += currentSpeed;

      // Reset stars that pass the camera
      if (posArray[i * 3 + 2] > 250) {
        posArray[i * 3 + 2] = -250;
      }
    }
    pointsRef.current.geometry.attributes.position.needsUpdate = true;

    // Streak elongation based on velocity
    // Note: We use points with size attenuation, but "warp" feeling comes from velocity + reset
    const material = pointsRef.current.material as THREE.PointsMaterial;
    material.size = THREE.MathUtils.lerp(material.size, isMobile ? 0.3 : (0.5 + velocity.current * 0.5), 0.1);

    // Mouse Tilt Parallax
    pointsRef.current.rotation.x = THREE.MathUtils.lerp(pointsRef.current.rotation.x, mouse.y * 0.1, 0.05);
    pointsRef.current.rotation.y = THREE.MathUtils.lerp(pointsRef.current.rotation.y, mouse.x * 0.1, 0.05);

    // Slow constant drift
    pointsRef.current.rotation.z += 0.0005;
  });

  return (
    <Points ref={pointsRef}>
      <BufferGeometry>
        <BufferAttribute
          attach="attributes-position"
          count={count}
          array={positions}
          itemSize={3}
        />
      </BufferGeometry>
      <PointsMaterial
        size={0.5}
        color={new THREE.Color("#ffffff")}
        transparent
        opacity={0.8}
        sizeAttenuation={true}
        blending={THREE.AdditiveBlending}
        depthWrite={false}
      />
    </Points>
  );
};

const Starfield: React.FC = () => {
  return (
    <div className="fixed inset-0 z-0 bg-[#050505] pointer-events-none">
      <Canvas 
        camera={{ position: [0, 0, 100], fov: 75, near: 0.1, far: 1000 }}
        dpr={[1, 2]}
      >
        <StarField />
