import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import Lenis from 'lenis';
import Header from './components/Header';
import Footer from './components/Footer';
import CurtainLoader from './components/CurtainLoader';
import CustomCursor from './components/CustomCursor';
import Starfield from './components/Starfield';
import Home from './pages/Home';
import Services from './pages/Services';
import Work from './pages/Work';
import Contact from './pages/Contact';

export type View = 'home' | 'services' | 'work' | 'contact';

const App: React.FC = () => {
  const [isLoaderActive, setIsLoaderActive] = useState(true);
  const [showContent, setShowContent] = useState(false);
  const [currentView, setCurrentView] = useState<View>('home');

  // Global Smooth Scroll
  useEffect(() => {
    const lenis = new Lenis({
      duration: 1.4,
      easing: (t) => Math.min(1, 1.001 - Math.pow(2, -10 * t)),
      orientation: 'vertical',
      smoothWheel: true,
      wheelMultiplier: 1.1,
    });

    function raf(time: number) {
      lenis.raf(time);
      requestAnimationFrame(raf);
    }

    requestAnimationFrame(raf);

    window.scrollTo(0, 0);
    return () => lenis.destroy();
  }, [currentView]);

  useEffect(() => {
    // Entrance sequence duration control
    const timer = setTimeout(() => {
      setIsLoaderActive(false);
      // Wait for panels to fully clear before allowing interaction
      setTimeout(() => setShowContent(true), 1200);
    }, 3500);
    return () => clearTimeout(timer);
  }, []);

  const renderView = () => {
    switch (currentView) {
      case 'home': return <Home onNavigate={setCurrentView} />;
      case 'services': return <Services />;
      case 'work': return <Work />;
      case 'contact': return <Contact />;
      default: return <Home onNavigate={setCurrentView} />;
    }
  };

  return (
    <div className="relative min-h-screen bg-[#050505] font-sans selection:bg-brand-blue selection:text-white overflow-x-hidden">
      <AnimatePresence mode="wait">
        {isLoaderActive && <CurtainLoader key="loader" />}
      </AnimatePresence>

      <CustomCursor />

      {/* PERSISTENT STELLAR ENGINE - Stays outside AnimatePresence to never blink */}
      <Starfield />

      {showContent && (
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ duration: 1.5, ease: "easeOut" }}
          className="relative z-20"
        >
          <Header currentView={currentView} onNavigate={setCurrentView} />

          <motion.main className="relative z-10 pt-20">
            <AnimatePresence mode="wait">
              <motion.div
                key={currentView}
                initial={{ opacity: 0, y: 30, filter: 'blur(10px)' }}
                animate={{ opacity: 1, y: 0, filter: 'blur(0px)' }}
                exit={{ opacity: 0, y: -30, filter: 'blur(10px)' }}
                transition={{ duration: 0.7, ease: [0.22, 1, 0.36, 1] }}
              >
                {renderView()}
              </motion.div>
            </AnimatePresence>
            <Footer onNavigate={setCurrentView} />
          </motion.main>
        </motion.div>
      )}
    </div>
  );
};

export default App;

