import React, { useRef, useMemo, useEffect, useState } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import * as THREE from 'three';

const Points = 'points' as any;
const BufferGeometry = 'bufferGeometry' as any;
const BufferAttribute = 'bufferAttribute' as any;
const PointsMaterial = 'pointsMaterial' as any;

const StarField = () => {
  const pointsRef = useRef<any>(null!);
  const [isMobile, setIsMobile] = useState(false);
  const scrollPos = useRef(0);
  const velocity = useRef(0);
  const lastScroll = useRef(0);
  const touchStart = useRef(0);

  useEffect(() => {
    const checkMobile = () => setIsMobile(window.innerWidth < 768);
    checkMobile();
    window.addEventListener('resize', checkMobile);

    const handleScroll = () => {
      scrollPos.current = window.scrollY;
    };

    const handleTouchMove = (e: TouchEvent) => {
      // Manual touch delta to support warp effect on swipe
      const touch = e.touches[0].clientY;
      const delta = Math.abs(touch - touchStart.current);
      velocity.current = THREE.MathUtils.lerp(velocity.current, delta * 0.05, 0.1);
      touchStart.current = touch;
    };

    const handleTouchStart = (e: TouchEvent) => {
      touchStart.current = e.touches[0].clientY;
    };

    window.addEventListener('scroll', handleScroll, { passive: true });
    window.addEventListener('touchstart', handleTouchStart, { passive: true });
    window.addEventListener('touchmove', handleTouchMove, { passive: true });

    return () => {
      window.removeEventListener('resize', checkMobile);
      window.removeEventListener('scroll', handleScroll);
      window.removeEventListener('touchstart', handleTouchStart);
      window.removeEventListener('touchmove', handleTouchMove);
    };
  }, []);

  // Optimized counts for performance
  const count = isMobile ? 1200 : 4500;

  const [positions, sizes] = useMemo(() => {
    const pos = new Float32Array(count * 3);
    const sz = new Float32Array(count);
    for (let i = 0; i < count; i++) {
      const r = 15 + Math.random() * 100;
      const theta = Math.random() * Math.PI * 2;
      pos[i * 3] = Math.cos(theta) * r;
      pos[i * 3 + 1] = Math.sin(theta) * r;
      pos[i * 3 + 2] = (Math.random() - 0.5) * 600;
      sz[i] = Math.random() * (isMobile ? 1.2 : 2);
    }
    return [pos, sz];
  }, [count, isMobile]);

  useFrame((state) => {
    const { mouse, clock } = state;

    // Calculate scroll velocity for Desktop
    const currentScroll = scrollPos.current;
    const scrollDelta = currentScroll - lastScroll.current;
    if (!isMobile) {
      velocity.current = THREE.MathUtils.lerp(velocity.current, Math.abs(scrollDelta) * 0.08, 0.05);
    } else {
      // Decay touch velocity
      velocity.current = THREE.MathUtils.lerp(velocity.current, 0, 0.05);
    }
    lastScroll.current = currentScroll;

    const baseSpeed = isMobile ? 0.15 : 0.25;
    const currentSpeed = baseSpeed + velocity.current * 2.5;

    const posArray = pointsRef.current.geometry.attributes.position.array as Float32Array;

    for (let i = 0; i < count; i++) {
      posArray[i * 3 + 2] += currentSpeed;
      if (posArray[i * 3 + 2] > 300) {
        posArray[i * 3 + 2] = -300;
      }
    }
    pointsRef.current.geometry.attributes.position.needsUpdate = true;

    const material = pointsRef.current.material as any;
    const targetSize = isMobile ? 0.25 : (0.45 + velocity.current * 0.4);
    material.size = THREE.MathUtils.lerp(material.size, targetSize, 0.1);

    // Mouse/Tilt Tilt Parallax
    const targetRotX = isMobile ? 0 : mouse.y * 0.08;
    const targetRotY = isMobile ? 0 : mouse.x * 0.08;
    pointsRef.current.rotation.x = THREE.MathUtils.lerp(pointsRef.current.rotation.x, targetRotX, 0.05);
    pointsRef.current.rotation.y = THREE.MathUtils.lerp(pointsRef.current.rotation.y, targetRotY, 0.05);

    pointsRef.current.rotation.z += 0.0004;
  });

  return (
    <Points ref={pointsRef}>
      <BufferGeometry>
        <BufferAttribute
          attach="attributes-position"
          count={count}
          array={positions}
          itemSize={3}
        />
      </BufferGeometry>
      <PointsMaterial
        size={0.4}
        color={new THREE.Color("#ffffff")}
        transparent
        opacity={isMobile ? 0.5 : 0.8}
        sizeAttenuation={true}
        blending={THREE.AdditiveBlending}
        depthWrite={false}
      />
    </Points>
  );
};

const Starfield: React.FC = () => {
  const [isMobile, setIsMobile] = useState(false);

  useEffect(() => {
    const checkMobile = () => setIsMobile(window.innerWidth < 768);
    checkMobile();
    window.addEventListener('resize', checkMobile);
    return () => window.removeEventListener('resize', checkMobile);
  }, []);

  return (
    <div className="fixed inset-0 z-0 bg-[#050505] pointer-events-none touch-none h-[100dvh]">
      <Canvas 
        camera={{ 
          position: [0, 0, 100], 
          fov: isMobile ? 75 : 55, 
          near: 0.1, 
          far: 1200 
        }}
        dpr={isMobile ? [1, 1.5] : [1, 2]}
        gl={{ antialias: false, powerPreference: "high-performance" }}
      >
        <StarField />
      </Canvas>
      <div className="absolute inset-0 bg-gradient-to-b from-[#050505] via-transparent to-[#050505] opacity-80" />
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,#050505_100%)] opacity-70" />
    </div>
  );
};

